export function usePowerUpHammer(game, row, col, element) {
    const tile = game.board[row][col];

    game.resetHintTimer();

    consumePowerUp(game, "hammer");
    updatePowerUpButtons(game);

    track("power_up_used", {
        level: game.currentLevel,
        power_up_type: "hammer",
        remaining_moves: game.maxMoves - game.movesUsed,
        uses_remaining: getTotalPowerUpCount(game, "hammer"),
    });

    game.animating = true;

    // Blocked with life: reduce life based on area size
    if (isBlockedWithLife(tile)) {
        const cellCount = tile.isRectangular ? (tile.rectWidth * tile.rectHeight) : 1;
        const reducedLife = tile.lifeValue - Math.ceil(tile.lifeValue / (cellCount + 1));

        if (reducedLife <= 0) {
            // Life depleted — remove tile(s)
            element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
            element.style.opacity = "0";
            element.style.transform = "scale(0)";

            setTimeout(() => {
                if (tile.isRectangular) {
                    for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
                        for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
                            game.board[r][c] = null;
                        }
                    }
                } else {
                    game.board[row][col] = null;
                }
                game.updateBlockedTileGoals();
                game.updateGoalDisplay(false);
                game.dropGems();
                deactivatePowerUp(game);
            }, 300);
        } else {
            // Reduce life value (mutate shared object so rectangular tiles stay consistent)
            tile.lifeValue = reducedLife;

            element.style.transform = "scale(1.2)";
            setTimeout(() => {
                element.style.transform = "scale(1)";
                game.renderBoard();
                game.updateGoalDisplay(false);
                game.animating = false;
            }, 200);

            deactivatePowerUp(game);
        }
        return;
    }

    // Rectangular merge-count blocked: decrement one cell
    if (isBlockedWithMergeCount(tile)) {
        // Find a cell with count > 0
        let cellToClear = null;
        for (const [cellKey, count] of Object.entries(tile.cellMergeCounts)) {
            if (count > 0) {
                cellToClear = cellKey;
                break;
            }
        }

        if (!cellToClear) return;

        tile.cellMergeCounts[cellToClear]--;

        // Check if all cells cleared
        const allCleared = Object.values(tile.cellMergeCounts).every((c) => c === 0);

        if (allCleared) {
            // Remove entire rectangular block
            for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
                for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
                    game.board[r][c] = null;
                }
            }
        }

        game.renderBoard();
        game.updateBlockedTileGoals();
        game.updateGoalDisplay(false);
        game.animating = false;
        if (allCleared) game.dropGems();
        deactivatePowerUp(game);
        return;
    }

    // Normal tile or blocked/blocked_movable: remove
    element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
    element.style.opacity = "0";
    element.style.transform = "scale(0)";

    setTimeout(() => {
        game.board[row][col] = null;
        game.updateBlockedTileGoals();
        game.updateGoalDisplay(false);
        game.dropGems();
        deactivatePowerUp(game);
    }, 300);
}

export function usePowerUpHalve(game, row, col, element) {
    const tile = game.board[row][col];
    const isCursedTile = isCursed(tile);
    const currentValue = tile && (tile.type === TILE_TYPE.NORMAL || isCursedTile) ? tile.value : null;

    if (currentValue && currentValue > 1) {
        game.resetHintTimer();

        consumePowerUp(game, "halve");
        updatePowerUpButtons(game);

